def test_manager_create_timesheet_missing_mandatory_field(
    api_client, auth_token_manager, db_session
):
    payload = {
        "employee_id": "EMP001",
        "start_date": "2024-01-01",
        "end_date": "2024-01-07",
        "description": "No hours"
    }
    headers = {"Authorization": f"Bearer {auth_token_manager}"}
    resp = api_client.post("/timesheets", json=payload, headers=headers)
    assert resp.status_code == 400
    error = resp.json()
    assert "hours" in error.get("message", "").lower()
    count = db_session.query(Timesheet).filter(
        Timesheet.employee_id == "EMP001"
    ).count()
    assert count == 0

def test_manager_create_timesheet_insufficient_role(
    api_client, auth_token_employee, db_session
):
    payload = {
        "employee_id": "EMP001",
        "start_date": "2024-01-01",
        "end_date": "2024-01-07",
        "hours": 40
    }
    headers = {"Authorization": f"Bearer {auth_token_employee}"}
    resp = api_client.post("/timesheets", json=payload, headers=headers)
    assert resp.status_code == 403
    count = db_session.query(Timesheet).count()
    assert count == 0
